mapper.select:
SELECT p.id, p.category, p.title, p.view_count, p.like_count, p.created_at, m.nickname AS author_nickname, m.id AS user_id, (SELECT COUNT(*) FROM comment c WHERE c.post_id = p.id) AS comment_count FROM post p JOIN member m ON p.member_id = m.id
AND p.category = #{category}
AND p.title LIKE CONCAT('%', #{keyword}, '%')
AND m.nickname LIKE CONCAT('%', #{keyword}, '%')
AND (p.title LIKE CONCAT('%', #{keyword}, '%') OR m.nickname LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY p.created_at DESC LIMIT #{limit} OFFSET #{offset}
